import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], av))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]}')

print(f'\n=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:10s} {u[2]:50s} {u[3]}')
"", "description": "Compare baseline vs after packages", "initial_wait": 60}

